40	const COMPONENT_TYPES = new Set(["rune"]);
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const sumBasePremiums = (items: Item[]): number => {
45	  const components = items.filter(isComponent);
46	  const nonComponents = items.filter((item) => !isComponent(item));
47	  const componentsTotal =
48	    components.length === 3 ? 60 : components.length * 25;
49	  const nonComponentsTotal = nonComponents.reduce(
50	    (sum, item) => sum + basePremiumFor(item),
51	    0,
52	  );
53	  return componentsTotal + nonComponentsTotal;
54	};
55	
56	const quote = (items: Item[]): QuoteResult => ({
57	  premium: sumBasePremiums(items) + PROCESSING_FEE,
58	});
59	
60	export const runScenario = (scenario: Scenario): ScenarioResult => ({
61	  results: scenario.steps.map((step) => quote(step.items)),
62	});
