const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsCost = (components: Item[]): number =>
  components.length === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : components.reduce((sum, item) => sum + basePremiumFor(item), 0);

const sumBasePremiums = (items: Item[]): number => {
  const [components, nonComponents] = partition(items, isComponent);
  const nonComponentsCost = nonComponents.reduce(
    (sum, item) => sum + basePremiumFor(item),
    0,
  );
  return componentsCost(components) + nonComponentsCost;
};

const partition = <T>(
  items: T[],
  predicate: (item: T) => boolean,
): [T[], T[]] => {
  const matching: T[] = [];
  const rest: T[] = [];
  for (const item of items) {
    (predicate(item) ? matching : rest).push(item);
  }
  return [matching, rest];
};

